// Prism Flock — flock shapes over liquid base with chromatic aberration
speed = 0.6

AUDIO.bins = 6; AUDIO.smooth = 0.80; AUDIO.gain = 30; AUDIO.apply();
var _lo = function(){ return a.fft[0] || 0 };
var _mi = function(){ return a.fft[2] || 0 };
var _hi = function(){ return a.fft[4] || 0 };
var low  = env(_lo, 0.4, 0.03);
var mid  = env(_mi, 0.35, 0.04);
var high = env(_hi, 0.3, 0.05);
var amp  = function(){ return (low() + mid() + high()) * 0.7 };

// BPM-synced shape sides — morphs on beat
var sides = [3, 5, 8, 200].fast(0.25).smooth(0.5)

// o1: liquid base (from 031 DNA)
osc(15, 0.08, 1.8)
  .color(
    () => 0.9 + low() * 0.5,
    () => 0.3 + mid() * 0.4,
    () => 0.6 + high() * 0.4
  )
  .modulate(noise(2.5, 0.3), 0.1)
  .blend(src(o0).hue(() => amp() * 0.006), 0.75)
  .colorama(() => 0.001 + amp() * 0.003)
  .out(o1)

// o2: flock shapes — repeated, drifting, audio-colored
shape(sides, 0.15, 0.02)
  .repeat(6, 4, () => Math.sin(time * 0.08) * 0.1, () => Math.cos(time * 0.06) * 0.08)
  .rotate(() => time * 0.03)
  .scrollX(() => Math.sin(time * 0.1) * 0.15)
  .scrollY(() => Math.cos(time * 0.08) * 0.1)
  .modulate(noise(1.5, 0.04), 0.06)
  .color(
    () => 0.8 + low() * 0.6,
    () => 0.4 + mid() * 0.5,
    () => 0.9 + high() * 0.4
  )
  .out(o2)

// o3: composite — shapes layered over liquid
src(o1)
  .add(src(o2).luma(0.15, 0.2), () => 0.3 + amp() * 0.3)
  .saturate(() => 1.3 + low() * 0.4)
  .contrast(() => 1.05 + low() * 0.08)
  .out(o3)

// final: chromatic aberration + feedback
src(o3)
  .r().scrollX(() => 0.0015 + low() * 0.001)
  .color(1.1, 0.1, 0.05)
  .add(
    src(o3).g()
    .scrollX(() => -(0.0008 + mid() * 0.0006))
    .color(0.2, 1.0, 0.15)
  )
  .add(
    src(o3).b()
    .scrollY(() => 0.0006 + high() * 0.0005)
    .color(0.08, 0.15, 0.85)
  )
  .blend(src(o0), 0.3)
  .brightness(() => 0.02 + low() * 0.02)
  .out(o0)
